const rows = $input.all().map(item => item.json);
const issues = rows.filter(row => row.is_valid_revenue === false || row.data_quality_issues?.length);
const totalRevenue = rows.filter(row => row.is_valid_revenue !== false).reduce((sum, row) => sum + Number(row.amount || 0), 0);
const pendingPayments = rows.filter(row => ['Pending', 'Overdue'].includes(row.payment_status)).reduce((sum, row) => sum + Number(row.amount || 0), 0);
const overdueRows = rows.filter(row => row.is_overdue === true || row.payment_status === 'Overdue');
const delayedRows = rows.filter(row => row.is_delayed === true);
return [{ json: { report_date: $now.toISODate(), total_orders: rows.length, data_quality_issue_count: issues.length, total_revenue: totalRevenue, pending_payments: pendingPayments, overdue_invoice_count: overdueRows.length, overdue_invoice_amount: overdueRows.reduce((sum, row) => sum + Number(row.amount || 0), 0), delayed_order_count: delayedRows.length, report_payload: { delayed_orders: delayedRows.map(row => row.order_id), quality_issues: issues.map(row => row.order_id) } } }];

const metrics = $('Code - Validate Data Quality And Calculate KPIs').first().json;
const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = typeof content === 'string' ? JSON.parse(content) : content; } catch (error) { parsed = { executive_summary: 'Insight generation failed; review KPI table directly.', risk_notes: ['llm_parse_error'], recommended_actions: ['manual review'] }; }
return [{ json: { ...metrics, insight_summary: parsed.executive_summary, risk_notes: parsed.risk_notes || [], recommended_actions: parsed.recommended_actions || [], model_name: $env.OPENROUTER_MODEL, prompt_version: 'dataops_insights_v1' } }];
